import { useState, useEffect, useRef } from "react";

const PHOTO_DATA = "data:image/jpeg;base64,";

const style = `
  @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=DM+Sans:wght@300;400;500&family=Playfair+Display:ital@1&display=swap');
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  :root {
    --yellow: #F5C518;
    --black: #0a0a0a;
    --dark: #111111;
    --white: #ffffff;
    --gray: #888888;
  }
  html { scroll-behavior: smooth; }
  body { background: var(--black); color: var(--white); font-family: 'DM Sans', sans-serif; overflow-x: hidden; cursor: none; }

  .cursor { position: fixed; width: 12px; height: 12px; background: var(--yellow); border-radius: 50%; pointer-events: none; z-index: 9999; transform: translate(-50%,-50%); transition: width .3s, height .3s; }
  .cursor-ring { position: fixed; width: 36px; height: 36px; border: 1.5px solid var(--yellow); border-radius: 50%; pointer-events: none; z-index: 9998; transform: translate(-50%,-50%); transition: transform .18s ease; opacity: .6; }

  /* NAV */
  nav { position: fixed; top: 0; left: 0; right: 0; z-index: 100; display: flex; align-items: center; justify-content: space-between; padding: 28px 60px; transition: background .4s, padding .4s; }
  nav.scrolled { background: rgba(10,10,10,0.92); backdrop-filter: blur(12px); padding: 18px 60px; border-bottom: 1px solid rgba(245,197,24,0.1); }
  .nav-logo { font-family: 'Bebas Neue', sans-serif; font-size: 28px; letter-spacing: 3px; color: var(--white); text-decoration: none; cursor: none; }
  .nav-logo span { color: var(--yellow); }
  .nav-links { display: flex; gap: 44px; list-style: none; }
  .nav-links a { font-size: 11px; letter-spacing: 2.5px; text-transform: uppercase; color: rgba(255,255,255,0.7); text-decoration: none; position: relative; transition: color .3s; cursor: none; }
  .nav-links a::after { content: ''; position: absolute; bottom: -4px; left: 0; width: 0; height: 1px; background: var(--yellow); transition: width .3s; }
  .nav-links a:hover { color: var(--yellow); }
  .nav-links a:hover::after { width: 100%; }
  .nav-links a.now-link { color: var(--yellow); }
  .nav-links a.now-link::before { content: ''; display: inline-block; width: 6px; height: 6px; background: var(--yellow); border-radius: 50%; margin-right: 6px; vertical-align: middle; animation: pulse 2s ease infinite; }
  @keyframes pulse { 0%,100% { opacity:1; transform: scale(1); } 50% { opacity:.4; transform: scale(1.4); } }
  .nav-cta { font-size: 11px; letter-spacing: 2px; text-transform: uppercase; padding: 12px 28px; border: 1px solid var(--yellow); color: var(--yellow); background: transparent; cursor: none; transition: background .3s, color .3s; text-decoration: none; }
  .nav-cta:hover { background: var(--yellow); color: var(--black); }

  /* HERO */
  .hero { position: relative; height: 100vh; min-height: 700px; background: var(--black); display: flex; align-items: center; overflow: hidden; }
  .hero-yellow-circle { position: absolute; width: 560px; height: 560px; background: var(--yellow); border-radius: 50%; top: 50%; left: 50%; transform: translate(-18%,-50%); z-index: 1; animation: circleIn 1.2s cubic-bezier(.16,1,.3,1) both; }
  @keyframes circleIn { from { transform: translate(-18%,-50%) scale(.4); opacity:0; } to { transform: translate(-18%,-50%) scale(1); opacity:1; } }
  .hero-photo { position: absolute; width: 460px; height: 580px; left: 50%; top: 50%; transform: translate(-42%,-50%); z-index: 2; object-fit: cover; object-position: center top; filter: grayscale(100%) contrast(1.1); animation: photoIn 1.4s cubic-bezier(.16,1,.3,1) .2s both; }
  @keyframes photoIn { from { transform: translate(-42%,-44%); opacity:0; } to { transform: translate(-42%,-50%); opacity:1; } }
  .hero-left { position: relative; z-index: 3; padding-left: 64px; max-width: 360px; animation: fadeUp 1s ease .6s both; }
  @keyframes fadeUp { from { transform: translateY(30px); opacity:0; } to { transform: translateY(0); opacity:1; } }
  .hero-tag { font-size: 10px; letter-spacing: 4px; text-transform: uppercase; color: var(--yellow); margin-bottom: 20px; display: flex; align-items: center; gap: 12px; }
  .hero-tag::before { content: ''; display: block; width: 32px; height: 1px; background: var(--yellow); }
  .hero-desc { font-size: 15px; line-height: 1.8; color: rgba(255,255,255,0.6); margin-bottom: 36px; font-weight: 300; }
  .hero-btns { display: flex; gap: 16px; flex-wrap: wrap; }
  .btn-primary { padding: 14px 36px; background: var(--yellow); color: var(--black); font-size: 11px; letter-spacing: 2px; text-transform: uppercase; font-weight: 500; border: none; cursor: none; transition: transform .2s, box-shadow .2s; text-decoration: none; display: inline-block; }
  .btn-primary:hover { transform: translateY(-3px); box-shadow: 0 12px 40px rgba(245,197,24,.3); }
  .btn-outline { padding: 14px 36px; background: transparent; color: var(--white); font-size: 11px; letter-spacing: 2px; text-transform: uppercase; font-weight: 400; border: 1px solid rgba(255,255,255,0.2); cursor: none; transition: border-color .3s, color .3s; text-decoration: none; display: inline-block; }
  .btn-outline:hover { border-color: var(--yellow); color: var(--yellow); }
  .hero-big-text { position: absolute; right: -5px; bottom: -35px; font-family: 'Bebas Neue', sans-serif; font-size: clamp(120px,18vw,255px); line-height: .85; color: var(--white); z-index: 3; letter-spacing: -2px; animation: textIn 1.2s cubic-bezier(.16,1,.3,1) .3s both; pointer-events: none; user-select: none; }
  @keyframes textIn { from { transform: translateX(60px); opacity:0; } to { transform: translateX(0); opacity:1; } }
  .hero-scroll-hint { position: absolute; bottom: 32px; left: 64px; z-index: 4; display: flex; align-items: center; gap: 14px; font-size: 10px; letter-spacing: 3px; text-transform: uppercase; color: rgba(255,255,255,.35); animation: fadeUp 1s ease 1.2s both; }
  .scroll-line { width: 40px; height: 1px; background: rgba(255,255,255,.2); position: relative; overflow: hidden; }
  .scroll-line::after { content: ''; position: absolute; top: 0; left: -100%; width: 100%; height: 100%; background: var(--yellow); animation: scrollAnim 2s ease infinite; }
  @keyframes scrollAnim { 0% { left:-100%; } 100% { left:100%; } }

  /* MARQUEE */
  .marquee-wrap { overflow: hidden; background: var(--yellow); padding: 20px 0; }
  .marquee-track { display: flex; animation: marquee 18s linear infinite; white-space: nowrap; }
  .marquee-item { font-family: 'Bebas Neue', sans-serif; font-size: 22px; letter-spacing: 4px; color: var(--black); padding: 0 40px; display: flex; align-items: center; gap: 24px; }
  .marquee-dot { width: 6px; height: 6px; border-radius: 50%; background: rgba(0,0,0,.3); flex-shrink: 0; }
  @keyframes marquee { from { transform: translateX(0); } to { transform: translateX(-50%); } }

  /* SECTION BASE */
  section { padding: 120px 60px; position: relative; }
  .section-tag { font-size: 10px; letter-spacing: 4px; text-transform: uppercase; color: var(--yellow); margin-bottom: 16px; display: flex; align-items: center; gap: 12px; }
  .section-tag::before { content: ''; width: 28px; height: 1px; background: var(--yellow); }
  .section-title { font-family: 'Bebas Neue', sans-serif; font-size: clamp(52px,7vw,96px); line-height: .92; letter-spacing: -1px; margin-bottom: 60px; }
  .section-title em { font-family: 'Playfair Display', serif; color: var(--yellow); font-style: italic; }

  /* ABOUT */
  .about-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 80px; align-items: center; }
  .about-photo-box { position: relative; }
  .about-img { width: 100%; aspect-ratio: 3/4; object-fit: cover; object-position: center top; filter: grayscale(100%) contrast(1.05); display: block; }
  .about-yellow-accent { position: absolute; width: 120px; height: 120px; background: var(--yellow); bottom: -20px; right: -20px; z-index: -1; }
  .about-text p { font-size: 16px; line-height: 1.9; color: rgba(255,255,255,.65); font-weight: 300; margin-bottom: 24px; }
  .about-text p strong { color: var(--white); font-weight: 500; }
  .about-highlights { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-top: 36px; }
  .highlight-item { padding: 20px; border: 1px solid rgba(255,255,255,.07); border-left: 3px solid var(--yellow); background: rgba(255,255,255,.02); }
  .highlight-title { font-size: 11px; letter-spacing: 2px; text-transform: uppercase; color: var(--yellow); margin-bottom: 6px; }
  .highlight-val { font-size: 14px; color: rgba(255,255,255,.7); }

  /* SKILLS */
  .skills-section { background: var(--dark); }
  .skills-grid { display: grid; grid-template-columns: repeat(3,1fr); gap: 2px; }
  .skill-card { padding: 48px 40px; background: var(--black); border: 1px solid rgba(255,255,255,.04); transition: background .3s, border-color .3s; cursor: none; position: relative; overflow: hidden; }
  .skill-card::before { content: ''; position: absolute; top: 0; left: 0; width: 0; height: 3px; background: var(--yellow); transition: width .4s; }
  .skill-card:hover { background: rgba(245,197,24,.04); border-color: rgba(245,197,24,.2); }
  .skill-card:hover::before { width: 100%; }
  .skill-icon { font-size: 36px; margin-bottom: 20px; }
  .skill-name { font-family: 'Bebas Neue', sans-serif; font-size: 28px; letter-spacing: 1px; margin-bottom: 12px; }
  .skill-desc { font-size: 13px; line-height: 1.7; color: rgba(255,255,255,.45); }
  .skill-tags { display: flex; flex-wrap: wrap; gap: 8px; margin-top: 20px; }
  .skill-tag { font-size: 10px; letter-spacing: 1.5px; text-transform: uppercase; padding: 5px 12px; border: 1px solid rgba(255,255,255,.1); color: rgba(255,255,255,.5); }

  /* ── NOW SECTION ── */
  .now-section { background: var(--black); position: relative; overflow: hidden; }
  .now-section::before { content: ''; position: absolute; top: -200px; right: -200px; width: 600px; height: 600px; background: radial-gradient(circle, rgba(245,197,24,0.07) 0%, transparent 70%); pointer-events: none; }

  .now-live-badge { display: inline-flex; align-items: center; gap: 10px; padding: 8px 20px; border: 1px solid rgba(245,197,24,0.3); background: rgba(245,197,24,0.06); margin-bottom: 48px; }
  .now-live-dot { width: 8px; height: 8px; border-radius: 50%; background: #4ade80; animation: pulse 2s ease infinite; flex-shrink: 0; }
  .now-live-text { font-size: 10px; letter-spacing: 3px; text-transform: uppercase; color: rgba(255,255,255,.6); }

  .now-grid { display: grid; grid-template-columns: 1.2fr 1fr 1fr; gap: 3px; margin-bottom: 3px; }
  .now-card { padding: 48px 44px; border: 1px solid rgba(255,255,255,.05); position: relative; overflow: hidden; transition: border-color .3s; }
  .now-card:hover { border-color: rgba(245,197,24,.2); }
  .now-card.philosophy { background: var(--yellow); grid-row: span 2; display: flex; flex-direction: column; justify-content: space-between; }
  .now-card.obsessed { background: var(--dark); }
  .now-card.looking { background: var(--dark); }
  .now-card.philosophy .now-card-label { font-size: 10px; letter-spacing: 4px; text-transform: uppercase; color: rgba(0,0,0,.5); margin-bottom: 32px; }
  .now-card.philosophy .now-card-title { font-family: 'Bebas Neue', sans-serif; font-size: 56px; line-height: .9; letter-spacing: -1px; color: var(--black); margin-bottom: 40px; }
  .now-quotes { display: flex; flex-direction: column; gap: 20px; }
  .now-quote { font-size: 15px; line-height: 1.6; color: rgba(0,0,0,.75); font-style: italic; padding-left: 16px; border-left: 2px solid rgba(0,0,0,.25); font-weight: 300; }
  .now-philosophy-footer { font-size: 11px; letter-spacing: 2px; text-transform: uppercase; color: rgba(0,0,0,.4); margin-top: 40px; }

  .now-card-label { font-size: 10px; letter-spacing: 4px; text-transform: uppercase; color: var(--yellow); margin-bottom: 24px; display: flex; align-items: center; gap: 10px; }
  .now-card-label::before { content: ''; width: 20px; height: 1px; background: var(--yellow); }
  .now-card-title { font-family: 'Bebas Neue', sans-serif; font-size: 40px; letter-spacing: 1px; color: var(--white); margin-bottom: 28px; line-height: 1; }
  .now-list { list-style: none; display: flex; flex-direction: column; gap: 14px; }
  .now-list li { font-size: 14px; line-height: 1.6; color: rgba(255,255,255,.6); font-weight: 300; display: flex; align-items: flex-start; gap: 12px; }
  .now-list li::before { content: '—'; color: var(--yellow); flex-shrink: 0; font-size: 12px; margin-top: 2px; }

  /* CONTACT */
  .contact-section { background: var(--yellow); }
  .contact-inner { display: grid; grid-template-columns: 1fr 1fr; gap: 80px; align-items: center; }
  .contact-section .section-tag { color: var(--black); }
  .contact-section .section-tag::before { background: var(--black); }
  .contact-section .section-title { color: var(--black); }
  .contact-section .section-title em { color: var(--black); opacity: .4; }
  .contact-desc { font-size: 16px; line-height: 1.8; color: rgba(0,0,0,.6); font-weight: 300; margin-bottom: 36px; }
  .contact-email { font-family: 'Bebas Neue', sans-serif; font-size: 28px; color: var(--black); letter-spacing: 2px; margin-bottom: 32px; display: block; text-decoration: none; }
  .contact-socials { display: flex; gap: 16px; }
  .social-btn { width: 44px; height: 44px; border: 1.5px solid rgba(0,0,0,.25); display: flex; align-items: center; justify-content: center; font-size: 14px; cursor: none; transition: background .2s, border-color .2s; text-decoration: none; color: var(--black); font-weight: 600; }
  .social-btn:hover { background: var(--black); border-color: var(--black); color: var(--yellow); }
  .contact-form { display: flex; flex-direction: column; gap: 16px; }
  .form-field { padding: 18px 24px; background: rgba(0,0,0,.08); border: 1px solid rgba(0,0,0,.15); border-bottom: 2px solid rgba(0,0,0,.2); font-size: 14px; color: var(--black); font-family: 'DM Sans', sans-serif; outline: none; transition: border-color .3s, background .3s; }
  .form-field::placeholder { color: rgba(0,0,0,.4); }
  .form-field:focus { border-color: var(--black); background: rgba(0,0,0,.05); }
  textarea.form-field { resize: none; height: 120px; }
  .submit-btn { padding: 18px; background: var(--black); color: var(--yellow); font-size: 11px; letter-spacing: 3px; text-transform: uppercase; font-weight: 500; border: none; cursor: none; font-family: 'DM Sans', sans-serif; transition: opacity .3s; }
  .submit-btn:hover { opacity: .85; }

  /* FOOTER */
  footer { background: #050505; padding: 40px 60px; display: flex; align-items: center; justify-content: space-between; border-top: 1px solid rgba(255,255,255,.05); }
  .footer-logo { font-family: 'Bebas Neue', sans-serif; font-size: 22px; letter-spacing: 3px; color: var(--white); }
  .footer-logo span { color: var(--yellow); }
  .footer-copy { font-size: 12px; letter-spacing: 1px; color: rgba(255,255,255,.25); }
  .footer-links { display: flex; gap: 32px; }
  .footer-links a { font-size: 10px; letter-spacing: 2px; text-transform: uppercase; color: rgba(255,255,255,.3); text-decoration: none; transition: color .3s; }
  .footer-links a:hover { color: var(--yellow); }

  /* NAV DOTS */
  .outline-panel { position: fixed; right: 0; top: 50%; transform: translateY(-50%); z-index: 200; display: flex; flex-direction: column; gap: 8px; padding: 16px 12px; background: rgba(10,10,10,.9); border-left: 1px solid rgba(245,197,24,.15); backdrop-filter: blur(8px); }
  .outline-dot { width: 8px; height: 8px; border-radius: 50%; border: 1.5px solid rgba(255,255,255,.2); cursor: none; transition: border-color .3s, background .3s; position: relative; }
  .outline-dot.active { border-color: var(--yellow); background: var(--yellow); }
  .outline-dot:hover::after { content: attr(data-label); position: absolute; right: 20px; top: 50%; transform: translateY(-50%); font-size: 10px; letter-spacing: 2px; text-transform: uppercase; color: var(--white); white-space: nowrap; background: rgba(10,10,10,.9); padding: 4px 10px; border: 1px solid rgba(245,197,24,.2); }


  /* MODAL */
  .modal-overlay { position: fixed; inset: 0; background: rgba(0,0,0,.75); backdrop-filter: blur(8px); z-index: 1000; display: flex; align-items: center; justify-content: center; animation: fadeIn .2s ease; }
  @keyframes fadeIn { from { opacity:0; } to { opacity:1; } }
  .modal-box { background: var(--dark); border: 1px solid rgba(245,197,24,.2); padding: 56px 52px; max-width: 520px; width: 90%; position: relative; animation: slideUp .3s cubic-bezier(.16,1,.3,1); }
  @keyframes slideUp { from { transform: translateY(24px); opacity:0; } to { transform: translateY(0); opacity:1; } }
  .modal-close { position: absolute; top: 20px; right: 24px; background: none; border: none; color: rgba(255,255,255,.4); font-size: 22px; cursor: none; transition: color .2s; line-height: 1; }
  .modal-close:hover { color: var(--yellow); }
  .modal-tag { font-size: 10px; letter-spacing: 4px; text-transform: uppercase; color: var(--yellow); margin-bottom: 16px; }
  .modal-title { font-family: 'Bebas Neue', sans-serif; font-size: 42px; letter-spacing: 1px; margin-bottom: 20px; line-height: 1; }
  .modal-body { font-size: 14px; line-height: 1.9; color: rgba(255,255,255,.55); font-weight: 300; }

  /* SOCIAL BUTTONS — larger with labels */
  .social-links { display: flex; gap: 14px; margin-top: 4px; }
  .social-link-btn { display: flex; align-items: center; gap: 10px; padding: 12px 24px; border: 1.5px solid rgba(0,0,0,.25); color: var(--black); text-decoration: none; font-size: 12px; letter-spacing: 1.5px; text-transform: uppercase; font-weight: 500; transition: background .2s, border-color .2s, transform .2s; cursor: none; }
  .social-link-btn:hover { background: var(--black); border-color: var(--black); color: var(--yellow); transform: translateY(-2px); }
  .social-link-btn svg { width: 16px; height: 16px; fill: currentColor; flex-shrink: 0; }

  /* FORM STATES */
  .form-success { display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 48px 24px; text-align: center; gap: 16px; }
  .form-success-icon { font-size: 48px; }
  .form-success-title { font-family: 'Bebas Neue', sans-serif; font-size: 36px; color: var(--black); letter-spacing: 1px; }
  .form-success-sub { font-size: 14px; color: rgba(0,0,0,.55); font-weight: 300; line-height: 1.7; }
  .submit-btn:disabled { opacity: .6; }
  .submit-btn .spinner { display: inline-block; width: 14px; height: 14px; border: 2px solid rgba(245,197,24,.3); border-top-color: var(--yellow); border-radius: 50%; animation: spin .7s linear infinite; margin-right: 10px; vertical-align: middle; }
  @keyframes spin { to { transform: rotate(360deg); } }
  .field-error { font-size: 11px; color: #ff6b6b; letter-spacing: 1px; margin-top: -8px; }

  /* FOOTER — updated */
  .footer-modal-links { display: flex; gap: 32px; }
  .footer-modal-links button { font-size: 10px; letter-spacing: 2px; text-transform: uppercase; color: rgba(255,255,255,.3); background: none; border: none; cursor: none; transition: color .3s; font-family: 'DM Sans', sans-serif; padding: 0; }
  .footer-modal-links button:hover { color: var(--yellow); }

  @media(max-width:900px){
    nav { padding: 20px 28px; }
    nav.scrolled { padding: 14px 28px; }
    .nav-links { display: none; }
    section { padding: 80px 28px; }
    .hero-left { padding-left: 28px; max-width: 260px; }
    .hero-big-text { font-size: clamp(80px,22vw,160px); }
    .hero-yellow-circle { width: 360px; height: 360px; }
    .hero-photo { width: 300px; height: 380px; }
    .about-grid, .contact-inner { grid-template-columns: 1fr; gap: 40px; }
    .skills-grid, .now-grid { grid-template-columns: 1fr; }
    .now-card.philosophy { grid-row: span 1; }
    footer { flex-direction: column; gap: 20px; text-align: center; }
    .outline-panel { display: none; }
  }
`;

